SELECT [External Linked Documents].[Source Type], [External Linked Documents].[Source No_], [External Linked Documents].[Source Line No_], [External Linked Documents].[Line No_], [External Linked Documents].[Document Type], [External Linked Documents].Description, [External Linked Documents].[Linked Document], [External Linked Documents].[Constant Assortment Var_Grp_], [External Linked Documents].[Constant Variable Code], Item.[Trademark Code], Item.[Season Code]
FROM Item INNER JOIN [External Linked Documents] ON (Item.[Model Item No_] = [External Linked Documents].[Source No_]) AND (Item.[Variable Group 01] = [External Linked Documents].[Constant Assortment Var_Grp_]) AND (Item.[Variable Code 01] = [External Linked Documents].[Constant Variable Code])
GROUP BY [External Linked Documents].[Source Type], [External Linked Documents].[Source No_], [External Linked Documents].[Source Line No_], [External Linked Documents].[Line No_], [External Linked Documents].[Document Type], [External Linked Documents].Description, [External Linked Documents].[Linked Document], [External Linked Documents].[Constant Assortment Var_Grp_], [External Linked Documents].[Constant Variable Code], Item.[Trademark Code], Item.[Season Code]
HAVING ((([External Linked Documents].[Source Type])=4));

